import React, { useState } from 'react';
import { useCartStore } from './cartStore';
import { useUserStore } from './userStore';
import { createOrder } from './woocommerce';

const Checkout = () => {
  const { cart, getCartTotal, clearCart } = useCartStore();
  const { user, isAuthenticated } = useUserStore();
  const [formData, setFormData] = useState({
    first_name: '',
    last_name: '',
    email: '',
    phone: '',
    address_1: '',
    address_2: '',
    city: '',
    state: '',
    postcode: '',
    country: 'IN'
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Pre-fill form if user is logged in
  React.useEffect(() => {
    if (isAuthenticated && user) {
      setFormData(prev => ({
        ...prev,
        first_name: user.first_name || '',
        last_name: user.last_name || '',
        email: user.email || '',
        phone: user.billing_phone || '',
        address_1: user.billing_address_1 || '',
        postcode: user.billing_postcode || ''
      }));
    }
  }, [isAuthenticated, user]);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const orderData = {
        payment_method: 'cod',
        payment_method_title: 'Cash on Delivery',
        set_paid: false,
        billing: formData,
        shipping: formData,
        line_items: cart.map(item => ({
          product_id: item.id,
          quantity: item.quantity
        }))
      };

      const order = await createOrder(orderData);

      // Clear cart and redirect
      clearCart();
      window.location.href = `/order-success/${order.id}`;
    } catch (err) {
      setError('Failed to create order. Please try again.');
      console.error('Order creation error:', err);
    } finally {
      setLoading(false);
    }
  };

  if (cart.length === 0) {
    return (
      <div className="checkout">
        <header className="header">
          <div className="header-content">
            <h1>Ritchie Street Electronics</h1>
            <nav className="nav">
              <Link to="/">Home</Link>
              <Link to="/cart">Cart ({getCartCount()})</Link>
              <Link to="/login">Login</Link>
            </nav>
          </div>
        </header>
        <div className="checkout-empty">
          <h2>Your cart is empty</h2>
          <Link to="/" className="continue-shopping">Continue Shopping</Link>
        </div>
      </div>
    );
  }

  return (
    <div className="checkout">
      <header className="header">
        <div className="header-content">
          <h1>Ritchie Street Electronics</h1>
          <nav className="nav">
            <Link to="/">Home</Link>
            <Link to="/cart">Cart ({getCartCount()})</Link>
            <Link to="/login">Login</Link>
          </nav>
        </div>
      </header>

      <div className="checkout-container">
        <div className="checkout-form">
          <h2>Checkout</h2>

          {error && <div className="error-message">{error}</div>}

          <form onSubmit={handleSubmit}>
            <h3>Billing Details</h3>

            <div className="form-row">
              <div className="form-group">
                <label>First Name *</label>
                <input
                  type="text"
                  name="first_name"
                  value={formData.first_name}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="form-group">
                <label>Last Name *</label>
                <input
                  type="text"
                  name="last_name"
                  value={formData.last_name}
                  onChange={handleChange}
                  required
                />
              </div>
            </div>

            <div className="form-group">
              <label>Email Address *</label>
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                required
              />
            </div>

            <div className="form-group">
              <label>Phone Number *</label>
              <input
                type="tel"
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                required
              />
            </div>

            <div className="form-group">
              <label>Address *</label>
              <input
                type="text"
                name="address_1"
                value={formData.address_1}
                onChange={handleChange}
                required
              />
            </div>

            <div className="form-group">
              <label>Apartment, suite, etc. (optional)</label>
              <input
                type="text"
                name="address_2"
                value={formData.address_2}
                onChange={handleChange}
              />
            </div>

            <div className="form-row">
              <div className="form-group">
                <label>City *</label>
                <input
                  type="text"
                  name="city"
                  value={formData.city}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="form-group">
                <label>State *</label>
                <input
                  type="text"
                  name="state"
                  value={formData.state}
                  onChange={handleChange}
                  required
                />
              </div>
            </div>

            <div className="form-group">
              <label>Postcode / ZIP *</label>
              <input
                type="text"
                name="postcode"
                value={formData.postcode}
                onChange={handleChange}
                required
              />
            </div>

            <h3>Payment Method</h3>
            <div className="payment-method">
              <label>
                <input type="radio" name="payment" value="cod" defaultChecked />
                Cash on Delivery
              </label>
            </div>

            <button type="submit" className="place-order-btn" disabled={loading}>
              {loading ? 'Processing...' : 'Place Order'}
            </button>
          </form>
        </div>

        <div className="order-summary">
          <h3>Your Order</h3>

          <div className="order-items">
            {cart.map(item => (
              <div key={item.id} className="order-item">
                <span>{item.name} × {item.quantity}</span>
                <span>₹{(parseFloat(item.price) * item.quantity).toFixed(2)}</span>
              </div>
            ))}
          </div>

          <div className="order-totals">
            <div className="total-row">
              <span>Subtotal</span>
              <span>₹{getCartTotal().toFixed(2)}</span>
            </div>
            <div className="total-row">
              <span>Shipping</span>
              <span>Free</span>
            </div>
            <div className="total-row final">
              <span>Total</span>
              <span>₹{getCartTotal().toFixed(2)}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Checkout;
